在 Linux 内核中，mdelay 函数的实现代码通常位于 include/linux/delay.h 这个头文件中。以下是 mdelay 函数的简化实现代码示例：

```c
#include <linux/delay.h>

void mdelay(unsigned int msec)
{
    unsigned long timeout = jiffies + msecs_to_jiffies(msec);

    while (time_before(jiffies, timeout))
    {
        // 暂时空转，直到延时结束
    }
}
```

在上面的代码中，mdelay 函数接收一个以毫秒为单位的延时时间，然后将当前的 jiffies 值加上相应的毫秒数，计算出超时时间点。接着通过一个 while 循环来忙等待，直到当前的 jiffies 值达到或超过超时时间点，即完成了指定的延时时间。

需要注意的是，这只是 mdelay 函数的一个简化实现代码示例，实际上内核中的 mdelay 函数可能会有一些优化和安全性处理，比如考虑到不同 CPU 频率下的精准延时，或者在 SMP 系统中的多 CPU 下的延时准确性等。

在 Linux 内核中，panic 函数用于触发系统崩溃，通常是在遇到严重错误或不可恢复的问题时调用。当 panic 函数被调用时，系统会停止正常运行并输出错误信息，最终进入内核崩溃状态。以下是简化的 panic 函数的源码示例：

```c
#include <linux/kernel.h>
#include <linux/init.h>
#include <linux/printk.h>

void panic(const char *fmt, ...)
{
    va_list args;
    va_start(args, fmt);
    pr_emerg("Kernel panic - not syncing: ");
    vprintk(fmt, args);
    va_end(args);

    // 停止系统运行
    machine_halt();
}
```

在上面的示例中，可以看到 panic 函数接收一个格式化字符串 fmt 和对应的可变参数。首先使用 va_list、va_start 和 va_end 宏来处理可变参数列表，然后使用 pr_emerg 和 vprintk 函数输出错误信息到系统控制台。最后调用 machine_halt() 函数来停止系统运行。注意，上面的示例是简化的，实际的 panic 函数可能包含更多处理和错误信息输出的逻辑。

需要指出的是，触发 panic 函数会导致系统崩溃，并且是一个极端的处理方式，仅在真正遇到系统无法恢复的严重错误时才会使用。panic 函数的调用通常会伴随着写好的错误信息，以便后续进行问题排查和调试。

void panic(const char *fmt, ...)
{
	static char buf[1024];
	va_list args;
	long i, i_next = 0, len;
	int state = 0;
	int old_cpu, this_cpu;
	bool _crash_kexec_post_notifiers = crash_kexec_post_notifiers;

	if (panic_on_warn) {
		/*
		 * This thread may hit another WARN() in the panic path.
		 * Resetting this prevents additional WARN() from panicking the
		 * system on this thread.  Other threads are blocked by the
		 * panic_mutex in panic().
		 */
		panic_on_warn = 0;
	}

	/*
	 * Disable local interrupts. This will prevent panic_smp_self_stop
	 * from deadlocking the first cpu that invokes the panic, since
	 * there is nothing to prevent an interrupt handler (that runs
	 * after setting panic_cpu) from invoking panic() again.
	 */
	local_irq_disable();
	preempt_disable_notrace();

	/*
	 * It's possible to come here directly from a panic-assertion and
	 * not have preempt disabled. Some functions called from here want
	 * preempt to be disabled. No point enabling it later though...
	 *
	 * Only one CPU is allowed to execute the panic code from here. For
	 * multiple parallel invocations of panic, all other CPUs either
	 * stop themself or will wait until they are stopped by the 1st CPU
	 * with smp_send_stop().
	 *
	 * cmpxchg success means this is the 1st CPU which comes here,
	 * so go ahead.
	 * `old_cpu == this_cpu' means we came from nmi_panic() which sets
	 * panic_cpu to this CPU.  In this case, this is also the 1st CPU.
	 */
	old_cpu = PANIC_CPU_INVALID;
	this_cpu = raw_smp_processor_id();

	/* atomic_try_cmpxchg updates old_cpu on failure */
	if (atomic_try_cmpxchg(&panic_cpu, &old_cpu, this_cpu)) {
		/* go ahead */
	} else if (old_cpu != this_cpu)
		panic_smp_self_stop();

	console_verbose();
	bust_spinlocks(1);
	va_start(args, fmt);
	len = vscnprintf(buf, sizeof(buf), fmt, args);
	va_end(args);

	if (len && buf[len - 1] == '\n')
		buf[len - 1] = '\0';

	pr_emerg("Kernel panic - not syncing: %s\n", buf);
#ifdef CONFIG_DEBUG_BUGVERBOSE
	/*
	 * Avoid nested stack-dumping if a panic occurs during oops processing
	 */
	if (!test_taint(TAINT_DIE) && oops_in_progress <= 1)
		dump_stack();
#endif

	/*
	 * If kgdb is enabled, give it a chance to run before we stop all
	 * the other CPUs or else we won't be able to debug processes left
	 * running on them.
	 */
	kgdb_panic(buf);

	/*
	 * If we have crashed and we have a crash kernel loaded let it handle
	 * everything else.
	 * If we want to run this after calling panic_notifiers, pass
	 * the "crash_kexec_post_notifiers" option to the kernel.
	 *
	 * Bypass the panic_cpu check and call __crash_kexec directly.
	 */
	if (!_crash_kexec_post_notifiers)
		__crash_kexec(NULL);

	panic_other_cpus_shutdown(_crash_kexec_post_notifiers);

	/*
	 * Run any panic handlers, including those that might need to
	 * add information to the kmsg dump output.
	 */
	atomic_notifier_call_chain(&panic_notifier_list, 0, buf);

	panic_print_sys_info(false);

	kmsg_dump(KMSG_DUMP_PANIC);

	/*
	 * If you doubt kdump always works fine in any situation,
	 * "crash_kexec_post_notifiers" offers you a chance to run
	 * panic_notifiers and dumping kmsg before kdump.
	 * Note: since some panic_notifiers can make crashed kernel
	 * more unstable, it can increase risks of the kdump failure too.
	 *
	 * Bypass the panic_cpu check and call __crash_kexec directly.
	 */
	if (_crash_kexec_post_notifiers)
		__crash_kexec(NULL);

	console_unblank();

	/*
	 * We may have ended up stopping the CPU holding the lock (in
	 * smp_send_stop()) while still having some valuable data in the console
	 * buffer.  Try to acquire the lock then release it regardless of the
	 * result.  The release will also print the buffers out.  Locks debug
	 * should be disabled to avoid reporting bad unlock balance when
	 * panic() is not being callled from OOPS.
	 */
	debug_locks_off();
	console_flush_on_panic(CONSOLE_FLUSH_PENDING);

	panic_print_sys_info(true);

	if (!panic_blink)
		panic_blink = no_blink;

	if (panic_timeout > 0) {
		/*
		 * Delay timeout seconds before rebooting the machine.
		 * We can't use the "normal" timers since we just panicked.
		 */
		pr_emerg("Rebooting in %d seconds..\n", panic_timeout);

		for (i = 0; i < panic_timeout * 1000; i += PANIC_TIMER_STEP) {
			touch_nmi_watchdog();
			if (i >= i_next) {
				i += panic_blink(state ^= 1);
				i_next = i + 3600 / PANIC_BLINK_SPD;
			}
			mdelay(PANIC_TIMER_STEP);
		}
	}
	if (panic_timeout != 0) {
		/*
		 * This will not be a clean reboot, with everything
		 * shutting down.  But if there is a chance of
		 * rebooting the system it will be rebooted.
		 */
		if (panic_reboot_mode != REBOOT_UNDEFINED)
			reboot_mode = panic_reboot_mode;
		emergency_restart();
	}
#ifdef __sparc__
	{
		extern int stop_a_enabled;
		/* Make sure the user can actually press Stop-A (L1-A) */
		stop_a_enabled = 1;
		pr_emerg("Press Stop-A (L1-A) from sun keyboard or send break\n"
			 "twice on console to return to the boot prom\n");
	}
#endif
#if defined(CONFIG_S390)
	disabled_wait();
#endif
	pr_emerg("---[ end Kernel panic - not syncing: %s ]---\n", buf);

	/* Do not scroll important messages printed above */
	suppress_printk = 1;
	local_irq_enable();
	for (i = 0; ; i += PANIC_TIMER_STEP) {
		touch_softlockup_watchdog();
		if (i >= i_next) {
			i += panic_blink(state ^= 1);
			i_next = i + 3600 / PANIC_BLINK_SPD;
		}
		mdelay(PANIC_TIMER_STEP);
	}
}这个是panic源码，哪个禁止中断和线程调度了

在给出的 panic 函数的源码中，以下部分代码用于禁止本地中断、禁止抢占，以及对 CPU 控制权的处理：

```c
local_irq_disable();
preempt_disable_notrace();
```

通过调用 local_irq_disable() 函数来禁止本地中断，从而防止中断处理程序的执行。另外，通过调用 preempt_disable_notrace() 函数来禁用抢占，确保当前任务在进行紧急处理时不会被其他高优先级任务打断。这两行代码会在 panic 函数被调用时执行，因此可以认为在 panic 期间将禁止中断和线程调度。在 Linux 内核中，这样的操作通常用于确保在内核发生严重错误时保持系统的稳定性。
